<?php
// backend/app/Policies/CustomerPolicy.php
// NOTE: Dung InternalUser (khong phai User) — nhat quan voi ContractPolicy, InvoicePolicy, CRC Policy.
// Dung resolveDepartmentIdsForUser() tu UserAccessService (khong phai resolveAccessibleDepartmentIds).
// Customer khong co truc tiep department_id — scope qua projects/contracts relationship.

namespace App\Policies;

use App\Models\Customer;
use App\Models\InternalUser;
use App\Policies\Concerns\ResolvesDepartmentScopedAccess;
use Illuminate\Auth\Access\HandlesAuthorization;

class CustomerPolicy
{
    use HandlesAuthorization;
    use ResolvesDepartmentScopedAccess;

    public function update(InternalUser $user, Customer $customer): bool
    {
        if ($user->hasRole('admin')) {
            return true;
        }

        // Customer scope: check via related contracts/projects department
        // (Customer model khong co department_id truc tiep)
        $userDeptIds = app(\App\Support\Auth\UserAccessService::class)
            ->resolveDepartmentIdsForUser($user);

        // Check neu customer co bat ky contract nao thuoc dept cua user
        return $customer->contracts()
            ->whereIn('department_id', $userDeptIds)
            ->exists();
    }

    public function delete(InternalUser $user, Customer $customer): bool
    {
        return $this->update($user, $customer);
    }
}
